import{_ as t,c as d,o,ag as a}from"./chunks/framework.Bw-5EFTY.js";const v=JSON.parse('{"title":"agent-event-service Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/agent-event-service/SPEC.md","filePath":"packages/agent-event-service/SPEC.md"}'),r={name:"packages/agent-event-service/SPEC.md"};function c(n,e,s,i,l,p){return o(),d("div",null,e[0]||(e[0]=[a(`<h1 id="agent-event-service-specification" tabindex="-1">agent-event-service Specification <a class="header-anchor" href="#agent-event-service-specification" aria-label="Permalink to &quot;agent-event-service Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p><code>@robota-sdk/agent-event-service</code> is a private, thin re-export layer that surfaces all event service types and implementations owned by <code>@robota-sdk/agent-core</code>. It exists so that consumers that previously depended on this package by name can continue to import from <code>@robota-sdk/agent-event-service</code> without requiring a migration to <code>@robota-sdk/agent-core</code> import paths.</p><p>This package owns no types, no implementations, and no business logic. Every symbol re-exported here is defined and maintained as SSOT in <code>@robota-sdk/agent-core</code>.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li><strong>Does not own</strong> any type definitions. All interfaces, type aliases, and classes are defined in <code>@robota-sdk/agent-core</code>.</li><li><strong>Does not own</strong> any runtime logic. Implementations (<code>DefaultEventService</code>, <code>StructuredEventService</code>, <code>ObservableEventService</code>, <code>AbstractEventService</code>) live in <code>@robota-sdk/agent-core</code>.</li><li><strong>Does not own</strong> event name constants (<code>TASK_EVENTS</code>, <code>TASK_EVENT_PREFIX</code>, <code>USER_EVENTS</code>, <code>USER_EVENT_PREFIX</code>). These are defined in <code>@robota-sdk/agent-core</code>.</li><li><strong>Not published</strong> to npm (<code>&quot;private&quot;: true</code>). It is a workspace-internal package only.</li><li>Consumers should prefer importing from <code>@robota-sdk/agent-core</code> directly for new code. This package is maintained for existing dependency paths only.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@robota-sdk/agent-event-service</span></span>
<span class="line"><span>└── src/index.ts   ← single file, 100% re-exports from @robota-sdk/agent-core</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         └──► @robota-sdk/agent-core   ← SSOT for all event types and implementations</span></span></code></pre></div><p>The package contains exactly one source file (<code>src/index.ts</code>) with no logic. All <code>export type { ... }</code> and <code>export { ... }</code> statements forward symbols from <code>@robota-sdk/agent-core</code>. No transformations, wrappers, or additional logic are introduced.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package owns <strong>zero</strong> SSOT types. All types below are defined in <code>@robota-sdk/agent-core</code> and re-exported here for compatibility.</p><table tabindex="0"><thead><tr><th>Type</th><th>SSOT Location</th><th>Purpose</th></tr></thead><tbody><tr><td><code>IEventService</code></td><td><code>@robota-sdk/agent-core</code></td><td>Contract for event emission and subscription</td></tr><tr><td><code>IBaseEventData</code></td><td><code>@robota-sdk/agent-core</code></td><td>Base shape for all event payloads</td></tr><tr><td><code>IAgentEventData</code></td><td><code>@robota-sdk/agent-core</code></td><td>Agent-scoped event payload shape</td></tr><tr><td><code>IExecutionEventData</code></td><td><code>@robota-sdk/agent-core</code></td><td>Execution-scoped event payload shape</td></tr><tr><td><code>IToolEventData</code></td><td><code>@robota-sdk/agent-core</code></td><td>Tool-scoped event payload shape</td></tr><tr><td><code>IEventContext</code></td><td><code>@robota-sdk/agent-core</code></td><td>Context attached to each emitted event</td></tr><tr><td><code>IEventServiceOwnerBinding</code></td><td><code>@robota-sdk/agent-core</code></td><td>Binding contract between an owner and its event service</td></tr><tr><td><code>IOwnerPathSegment</code></td><td><code>@robota-sdk/agent-core</code></td><td>Single segment of the owner path hierarchy</td></tr><tr><td><code>TEventListener</code></td><td><code>@robota-sdk/agent-core</code></td><td>Listener callback type for event subscriptions</td></tr><tr><td><code>TEventLoggerData</code></td><td><code>@robota-sdk/agent-core</code></td><td>Data shape passed to event loggers</td></tr><tr><td><code>TEventUniversalValue</code></td><td><code>@robota-sdk/agent-core</code></td><td>Scalar value type used in event payloads</td></tr><tr><td><code>IEventObjectValue</code></td><td><code>@robota-sdk/agent-core</code></td><td>Object value type used in event payloads</td></tr><tr><td><code>TEventExtensionValue</code></td><td><code>@robota-sdk/agent-core</code></td><td>Extension value type for custom event fields</td></tr><tr><td><code>TUserEvent</code></td><td><code>@robota-sdk/agent-core</code></td><td>Union type of all user-defined event names</td></tr></tbody></table><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><p>All exports are re-exports from <code>@robota-sdk/agent-core</code>. The table below lists every symbol currently exported by <code>src/index.ts</code>.</p><h3 id="type-exports" tabindex="-1">Type Exports <a class="header-anchor" href="#type-exports" aria-label="Permalink to &quot;Type Exports&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>IEventService</code></td><td><code>interface</code></td><td>Primary contract for event services</td></tr><tr><td><code>IBaseEventData</code></td><td><code>interface</code></td><td>Base event payload structure</td></tr><tr><td><code>IAgentEventData</code></td><td><code>interface</code></td><td>Agent-level event payload</td></tr><tr><td><code>IExecutionEventData</code></td><td><code>interface</code></td><td>Execution-level event payload</td></tr><tr><td><code>IToolEventData</code></td><td><code>interface</code></td><td>Tool-level event payload</td></tr><tr><td><code>IEventContext</code></td><td><code>interface</code></td><td>Event emission context</td></tr><tr><td><code>IEventServiceOwnerBinding</code></td><td><code>interface</code></td><td>Owner–service binding contract</td></tr><tr><td><code>IOwnerPathSegment</code></td><td><code>interface</code></td><td>Owner path hierarchy segment</td></tr><tr><td><code>TEventListener</code></td><td><code>type alias</code></td><td>Event listener callback signature</td></tr><tr><td><code>TEventLoggerData</code></td><td><code>type alias</code></td><td>Logger data shape</td></tr><tr><td><code>TEventUniversalValue</code></td><td><code>type alias</code></td><td>Scalar value union for event fields</td></tr><tr><td><code>IEventObjectValue</code></td><td><code>interface</code></td><td>Object value shape for event fields</td></tr><tr><td><code>TEventExtensionValue</code></td><td><code>type alias</code></td><td>Extension value union for event fields</td></tr><tr><td><code>TUserEvent</code></td><td><code>type alias</code></td><td>User-defined event name union</td></tr></tbody></table><h3 id="value-exports" tabindex="-1">Value Exports <a class="header-anchor" href="#value-exports" aria-label="Permalink to &quot;Value Exports&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>AbstractEventService</code></td><td><code>abstract class</code></td><td>Base class for all event service implementations</td></tr><tr><td><code>DefaultEventService</code></td><td><code>class</code></td><td>Null-object implementation (no-op event service)</td></tr><tr><td><code>StructuredEventService</code></td><td><code>class</code></td><td>Full implementation with structured event emission</td></tr><tr><td><code>ObservableEventService</code></td><td><code>class</code></td><td>Observable-pattern event service implementation</td></tr><tr><td><code>DEFAULT_ABSTRACT_EVENT_SERVICE</code></td><td><code>const</code></td><td>Shared singleton of the default (no-op) service</td></tr><tr><td><code>isDefaultEventService</code></td><td><code>function</code></td><td>Type guard to check if a service is the default no-op</td></tr><tr><td><code>bindEventServiceOwner</code></td><td><code>function</code></td><td>Binds an owner object to an event service</td></tr><tr><td><code>bindWithOwnerPath</code></td><td><code>function</code></td><td>Binds a service with an explicit owner path</td></tr><tr><td><code>composeEventName</code></td><td><code>function</code></td><td>Composes a namespaced event name string</td></tr><tr><td><code>TASK_EVENTS</code></td><td><code>const</code></td><td>Map of task event name constants</td></tr><tr><td><code>TASK_EVENT_PREFIX</code></td><td><code>const</code></td><td>Prefix string for all task event names</td></tr><tr><td><code>USER_EVENTS</code></td><td><code>const</code></td><td>Map of user event name constants</td></tr><tr><td><code>USER_EVENT_PREFIX</code></td><td><code>const</code></td><td>Prefix string for all user event names</td></tr></tbody></table><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><p>This package exposes no extension points of its own. Extension is performed through <code>@robota-sdk/agent-core</code>:</p><ul><li>Extend <code>AbstractEventService</code> (from <code>@robota-sdk/agent-core</code>) to implement a custom event service.</li><li>Implement <code>IEventService</code> (from <code>@robota-sdk/agent-core</code>) directly for a fully custom implementation.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>This package defines no error types. It contains no runtime logic and cannot throw package-specific errors. Any errors originate in <code>@robota-sdk/agent-core</code> implementations.</p><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><p>No tests are required or maintained in this package. The package contains a single file with pure re-exports and no logic to test.</p><p>The <code>vitest</code> devDependency and <code>test</code> script are present for workspace consistency. The script runs with <code>--passWithNoTests</code>.</p><p>Logic correctness is validated by tests in <code>@robota-sdk/agent-core</code>, which owns all implementations.</p><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><p>This package contains no classes, no <code>implements</code> clauses, and no <code>extends</code> clauses. All class definitions are in <code>@robota-sdk/agent-core</code>.</p><table tabindex="0"><thead><tr><th>Export re-exported</th><th>Defined in</th><th>Contract</th></tr></thead><tbody><tr><td><code>AbstractEventService</code></td><td><code>@robota-sdk/agent-core</code></td><td>Implements <code>IEventService</code></td></tr><tr><td><code>DefaultEventService</code></td><td><code>@robota-sdk/agent-core</code></td><td>Extends <code>AbstractEventService</code> (null-object)</td></tr><tr><td><code>StructuredEventService</code></td><td><code>@robota-sdk/agent-core</code></td><td>Extends <code>AbstractEventService</code></td></tr><tr><td><code>ObservableEventService</code></td><td><code>@robota-sdk/agent-core</code></td><td>Extends <code>AbstractEventService</code></td></tr></tbody></table><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependency</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>@robota-sdk/agent-core</code></td><td>production (<code>workspace:*</code>)</td><td>SSOT for all re-exported types and implementations</td></tr></tbody></table><p>No other production dependencies. Build tooling (<code>tsup</code>, <code>typescript</code>, <code>vitest</code>, <code>rimraf</code>) are devDependencies only.</p><h2 id="known-consumers" tabindex="-1">Known Consumers <a class="header-anchor" href="#known-consumers" aria-label="Permalink to &quot;Known Consumers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Consumer</th><th>Import pattern</th></tr></thead><tbody><tr><td><code>agent-playground</code></td><td>Imports event types and services by name from this package</td></tr><tr><td><code>agent-team</code></td><td>Imports event types and services by name from this package</td></tr></tbody></table>`,35)]))}const b=t(r,[["render",c]]);export{v as __pageData,b as default};
